previewCss:
.darma-loader-darma-custom-246 {
  color: var(--loader-color, #0891b2);
  display: inline-grid;
}
.darma-loader-darma-custom-246:before,
.darma-loader-darma-custom-246:after {
  content: "";
  height: 27px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  clip-path: inset(0 60% 0 0);
  animation: darma-loader-darma-custom-246-l7 .8s infinite linear alternate;
}
.darma-loader-darma-custom-246:after {
  animation-direction: alternate-reverse;
}
@keyframes darma-loader-darma-custom-246-l7{
  to {clip-path: inset(0 0 0 60%)}
}

